/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Validates phone numbers, formats messages, and sends via a configurable transport.
 * Follows the same patterns as EmailAdapter and WebhookAdapter:
 * - Never throws — returns { success: false, error } on failure
 * - Configurable transport function for testing vs production
 * - In-memory message tracking for testing (getSentMessages / clearSentMessages)
 *
 * NOTE: User preferences (src/models/user-preferences.ts) currently only model
 * email preferences. SMS channel preferences (enabled, subscribedTypes, quiet hours)
 * need to be added before SMS notifications respect user opt-out settings.
 * See the warning posted to the Twining blackboard for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Represents a sent SMS message. */
export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/** Configuration for the SmsAdapter. */
export interface SmsAdapterConfig {
  /** Sender phone number or short code. */
  from: string;
  /** Optional function to resolve a recipient identifier to a phone number. */
  resolveRecipient?: (recipient: string) => Promise<string | undefined>;
  /** Optional custom transport function (e.g., Twilio, SNS). Default: in-memory store. */
  transport?: (message: SmsMessage) => Promise<void>;
}

/** A fully formatted SMS message ready for transport. */
export interface SmsMessage {
  from: string;
  to: string;
  body: string;
  metadata?: Record<string, unknown>;
}

/**
 * E.164 phone number format: + followed by 1-15 digits.
 * This is the international standard for phone number formatting.
 */
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

/**
 * Maximum SMS body length (standard single SMS is 160 chars).
 * Messages longer than this will be truncated with an ellipsis.
 */
const MAX_SMS_LENGTH = 160;

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private config: SmsAdapterConfig;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = {
      from: config?.from ?? '+10000000000',
      resolveRecipient: config?.resolveRecipient,
      transport: config?.transport,
    };
  }

  /**
   * Resolve the recipient to a valid phone number.
   * If the recipient is already an E.164 phone number, returns it directly.
   * Otherwise, uses the configured resolveRecipient function.
   */
  async resolveRecipientPhone(recipient: string): Promise<string | undefined> {
    if (PHONE_REGEX.test(recipient)) {
      return recipient;
    }
    if (this.config.resolveRecipient) {
      return this.config.resolveRecipient(recipient);
    }
    return undefined;
  }

  /**
   * Validate that a phone number is in E.164 format.
   */
  static validatePhone(phone: string): boolean {
    return PHONE_REGEX.test(phone);
  }

  /**
   * Format the notification payload into an SMS message body.
   * Combines subject and body, truncating to SMS length limit.
   */
  formatMessage(payload: NotificationPayload): string {
    const full = `${payload.subject}: ${payload.body}`;
    if (full.length <= MAX_SMS_LENGTH) {
      return full;
    }
    return full.substring(0, MAX_SMS_LENGTH - 3) + '...';
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Resolve recipient
      const resolvedPhone = await this.resolveRecipientPhone(payload.recipient);
      if (!resolvedPhone) {
        const msg = `Could not resolve recipient to phone number: ${payload.recipient}`;
        this.logger.warn(msg);
        return { success: false, error: msg };
      }

      // 2. Validate phone format
      if (!SmsAdapter.validatePhone(resolvedPhone)) {
        const msg = `Invalid phone number: ${resolvedPhone}`;
        this.logger.warn(msg);
        return { success: false, error: msg };
      }

      // 3. Format message
      const body = this.formatMessage(payload);
      const message: SmsMessage = {
        from: this.config.from,
        to: resolvedPhone,
        body,
        metadata: payload.metadata,
      };

      // 4. Send via transport
      if (this.config.transport) {
        await this.config.transport(message);
      }

      // 5. Record sent message
      const sent: SentSms = {
        to: resolvedPhone,
        body,
        sentAt: new Date(),
        metadata: payload.metadata,
      };
      this.sentMessages.push(sent);

      this.logger.info(`SMS sent to ${resolvedPhone}`);
      return { success: true };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /** Get all sent messages. Useful for testing. */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /** Clear sent messages. Useful for testing. */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { SmsMessage } from '../../src/adapters/sms.adapter.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Confirmed',
    body: 'Your order has been placed.',
    channel: 'sms',
    type: 'order_confirmation',
    priority: 'normal',
    metadata: { orderId: 'order-123' },
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('send', () => {
    it('should send SMS for a valid phone number recipient', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('Order Confirmed');
      expect(sent[0]?.body).toContain('Your order has been placed.');
    });

    it('should fail for unresolvable non-phone recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient to phone number');
    });

    it('should fail for invalid phone number format', async () => {
      const result = await adapter.send(makePayload({ recipient: '555-1234' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient to phone number');
    });

    it('should handle transport errors gracefully', async () => {
      const failingAdapter = new SmsAdapter({
        transport: async () => {
          throw new Error('SMS gateway unavailable');
        },
      });
      const result = await failingAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
    });

    it('should call custom transport with formatted message', async () => {
      const transportSpy = vi.fn<[SmsMessage], Promise<void>>().mockResolvedValue(undefined);
      const customAdapter = new SmsAdapter({ transport: transportSpy });

      await customAdapter.send(makePayload());

      expect(transportSpy).toHaveBeenCalledOnce();
      const message = transportSpy.mock.calls[0]?.[0];
      expect(message?.from).toBe('+10000000000');
      expect(message?.to).toBe('+15551234567');
      expect(message?.body).toContain('Order Confirmed');
    });
  });

  describe('recipient resolution', () => {
    it('should pass through valid E.164 phone numbers', async () => {
      const phone = await adapter.resolveRecipientPhone('+447911123456');
      expect(phone).toBe('+447911123456');
    });

    it('should return undefined for non-phone without resolver', async () => {
      const phone = await adapter.resolveRecipientPhone('user-456');
      expect(phone).toBeUndefined();
    });

    it('should use resolveRecipient function for non-phone recipients', async () => {
      const resolver = vi.fn().mockResolvedValue('+15559876543');
      const adapterWithResolver = new SmsAdapter({ resolveRecipient: resolver });

      const result = await adapterWithResolver.send(makePayload({ recipient: 'user-789' }));
      expect(result.success).toBe(true);
      expect(resolver).toHaveBeenCalledWith('user-789');

      const sent = adapterWithResolver.getSentMessages();
      expect(sent[0]?.to).toBe('+15559876543');
    });

    it('should fail when resolver returns undefined', async () => {
      const resolver = vi.fn().mockResolvedValue(undefined);
      const adapterWithResolver = new SmsAdapter({ resolveRecipient: resolver });

      const result = await adapterWithResolver.send(makePayload({ recipient: 'unknown-user' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient to phone number');
    });
  });

  describe('message formatting', () => {
    it('should combine subject and body', () => {
      const message = adapter.formatMessage(makePayload());
      expect(message).toBe('Order Confirmed: Your order has been placed.');
    });

    it('should truncate messages exceeding 160 characters', () => {
      const longBody = 'A'.repeat(200);
      const message = adapter.formatMessage(makePayload({ body: longBody }));
      expect(message.length).toBe(160);
      expect(message.endsWith('...')).toBe(true);
    });

    it('should not truncate messages at exactly 160 characters', () => {
      // "Order Confirmed: " is 17 chars, so body needs to be 143 chars for exactly 160
      const exactBody = 'B'.repeat(143);
      const message = adapter.formatMessage(makePayload({ body: exactBody }));
      expect(message.length).toBe(160);
      expect(message.endsWith('...')).toBe(false);
    });
  });

  describe('phone validation', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(SmsAdapter.validatePhone('+15551234567')).toBe(true);
      expect(SmsAdapter.validatePhone('+447911123456')).toBe(true);
      expect(SmsAdapter.validatePhone('+1')).toBe(false); // Too short — need at least 2 digits
    });

    it('should reject invalid phone numbers', () => {
      expect(SmsAdapter.validatePhone('5551234567')).toBe(false);
      expect(SmsAdapter.validatePhone('+0123456789')).toBe(false);
      expect(SmsAdapter.validatePhone('')).toBe(false);
      expect(SmsAdapter.validatePhone('not-a-phone')).toBe(false);
      expect(SmsAdapter.validatePhone('+1234567890123456')).toBe(false); // Too long
    });
  });

  describe('configuration', () => {
    it('should use default from number', async () => {
      const transportSpy = vi.fn<[SmsMessage], Promise<void>>().mockResolvedValue(undefined);
      const defaultAdapter = new SmsAdapter({ transport: transportSpy });
      await defaultAdapter.send(makePayload());

      const message = transportSpy.mock.calls[0]?.[0];
      expect(message?.from).toBe('+10000000000');
    });

    it('should use custom from number', async () => {
      const transportSpy = vi.fn<[SmsMessage], Promise<void>>().mockResolvedValue(undefined);
      const custom = new SmsAdapter({ from: '+18005551234', transport: transportSpy });
      await custom.send(makePayload());

      const message = transportSpy.mock.calls[0]?.[0];
      expect(message?.from).toBe('+18005551234');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should track and clear sent messages', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559999999' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return a copy of sent messages', async () => {
      await adapter.send(makePayload());
      const messages = adapter.getSentMessages();
      messages.pop();
      expect(adapter.getSentMessages()).toHaveLength(1);
    });
  });
});

